import{c as e,Q as t,j as o,m as i}from"./chunks/framework.BA1dEi98.js";const r="/librislog/next/screenshots/library-read.png",g=JSON.parse('{"title":"Library","description":"","frontmatter":{},"headers":[],"relativePath":"guide/using-librislog/library.md","filePath":"guide/using-librislog/library.md","lastUpdated":1780089472000}'),l={name:"guide/using-librislog/library.md"};function s(n,a,d,c,h,u){return t(),o("div",null,[...a[0]||(a[0]=[i('<h1 id="library" tabindex="-1">Library <a class="header-anchor" href="#library" aria-label="Permalink to &quot;Library&quot;">​</a></h1><p>The library is the heart of LibrisLog. It organizes your books into four reading statuses and provides tools for managing your collection.</p><h2 id="reading-statuses" tabindex="-1">Reading Statuses <a class="header-anchor" href="#reading-statuses" aria-label="Permalink to &quot;Reading Statuses&quot;">​</a></h2><p>Books are categorized into four statuses:</p><table tabindex="0"><thead><tr><th>Status</th><th>Description</th></tr></thead><tbody><tr><td><strong>Want to Read</strong></td><td>Books you plan to read</td></tr><tr><td><strong>Currently Reading</strong></td><td>Books you&#39;re actively reading</td></tr><tr><td><strong>Read</strong></td><td>Books you&#39;ve finished</td></tr><tr><td><strong>Did Not Finish</strong></td><td>Books you started but abandoned</td></tr></tbody></table><p>Each status has its own tab in the library view, making it easy to browse your collection by reading state.</p><p><img src="'+r+'" alt="Library" loading="lazy"></p><h2 id="navigation" tabindex="-1">Navigation <a class="header-anchor" href="#navigation" aria-label="Permalink to &quot;Navigation&quot;">​</a></h2><ul><li>Switch between tabs using the bottom navigation bar on mobile or the sidebar on desktop</li><li>Books are displayed as cards with cover images, titles, and authors</li><li>Click any book to open the detail view</li></ul><h2 id="book-cards" tabindex="-1">Book Cards <a class="header-anchor" href="#book-cards" aria-label="Permalink to &quot;Book Cards&quot;">​</a></h2><p>Each book card shows:</p><ul><li>Cover image (or placeholder if no cover)</li><li>Title and author</li><li>Current reading progress (for &quot;Currently Reading&quot; books)</li><li>Star rating (for &quot;Read&quot; books)</li></ul><h2 id="detail-view" tabindex="-1">Detail View <a class="header-anchor" href="#detail-view" aria-label="Permalink to &quot;Detail View&quot;">​</a></h2><p>Clicking a book opens the detail dialog/drawer showing:</p><ul><li>Full cover image</li><li>Complete metadata (title, subtitle, author, ISBN, publisher, year, pages, language)</li><li>Reading status badge</li><li>Star rating (clickable to change)</li><li>Reading progress slider (for books with page count)</li><li>Tags</li><li>Notes</li><li>Blurb/description with expand/collapse</li><li>Action buttons: Edit, Delete</li></ul><h2 id="adding-books" tabindex="-1">Adding Books <a class="header-anchor" href="#adding-books" aria-label="Permalink to &quot;Adding Books&quot;">​</a></h2><h3 id="manual-entry" tabindex="-1">Manual Entry <a class="header-anchor" href="#manual-entry" aria-label="Permalink to &quot;Manual Entry&quot;">​</a></h3><p>Use the &quot;Add Book&quot; button to manually enter book details. Fill in title, author, and optional fields like ISBN, publisher, page count, etc.</p><h3 id="import-search" tabindex="-1">Import Search <a class="header-anchor" href="#import-search" aria-label="Permalink to &quot;Import Search&quot;">​</a></h3><p>Search external sources for book metadata:</p><ul><li><strong>Open Library</strong> — Free, no API key required</li><li><strong>Google Books</strong> — Requires API key (set in <code>.env</code>)</li><li><strong>Hardcover.app</strong> — Requires API token (set in <code>.env</code>)</li></ul><p>The search automatically tries Open Library first, then falls back to other sources. For ISBN searches, all available sources are queried in parallel.</p><h3 id="isbn-barcode-scan" tabindex="-1">ISBN Barcode Scan <a class="header-anchor" href="#isbn-barcode-scan" aria-label="Permalink to &quot;ISBN Barcode Scan&quot;">​</a></h3><p>On mobile devices, use the camera to scan ISBN barcodes. The app uses the device&#39;s camera with real-time barcode detection to quickly look up books.</p><h2 id="editing-books" tabindex="-1">Editing Books <a class="header-anchor" href="#editing-books" aria-label="Permalink to &quot;Editing Books&quot;">​</a></h2><p>Click the &quot;Edit&quot; button in the detail view to modify any book property. Changes are saved immediately.</p><h2 id="covers" tabindex="-1">Covers <a class="header-anchor" href="#covers" aria-label="Permalink to &quot;Covers&quot;">​</a></h2><h3 id="automatic-cover-search" tabindex="-1">Automatic Cover Search <a class="header-anchor" href="#automatic-cover-search" aria-label="Permalink to &quot;Automatic Cover Search&quot;">​</a></h3><p>When adding a book, the app automatically searches for cover images from:</p><ul><li>AbeBooks</li><li>Open Library</li><li>Amazon</li><li>Hardcover</li></ul><h3 id="cover-picker" tabindex="-1">Cover Picker <a class="header-anchor" href="#cover-picker" aria-label="Permalink to &quot;Cover Picker&quot;">​</a></h3><p>If automatic search doesn&#39;t find a suitable cover, you can:</p><ul><li>Upload an image file</li><li>Paste an image URL</li><li>Trigger a manual cover search</li></ul><h3 id="cover-caching" tabindex="-1">Cover Caching <a class="header-anchor" href="#cover-caching" aria-label="Permalink to &quot;Cover Caching&quot;">​</a></h3><p>Downloaded covers are cached locally in the <code>COVERS_DIR</code> directory to avoid repeated external requests.</p><h2 id="search" tabindex="-1">Search <a class="header-anchor" href="#search" aria-label="Permalink to &quot;Search&quot;">​</a></h2><ul><li>Search books by title, author, or tags using the search bar — the result count updates as you type</li><li>Press <strong>Enter</strong> to open the dedicated search results page with a full results grid, load-more pagination, and the same book detail interaction as the library</li><li>From any page, navigate directly to <code>/search?q=your+query</code> for quick access</li></ul><h2 id="sort" tabindex="-1">Sort <a class="header-anchor" href="#sort" aria-label="Permalink to &quot;Sort&quot;">​</a></h2><ul><li>Sort by title, date added, date started, date finished, or rating</li><li>Sort order: ascending or descending</li></ul><h2 id="view-modes" tabindex="-1">View Modes <a class="header-anchor" href="#view-modes" aria-label="Permalink to &quot;View Modes&quot;">​</a></h2><p>Switch between grid view (cover-focused) and list view (compact) using the view toggle.</p>',41)])])}const p=e(l,[["render",s]]);export{g as __pageData,p as default};
